usage_example:
```hcl
resource "betterado_release_definition" "example" {
  name                = "MyApp Release"
  project_id          = data.betterado_project.example.id
  release_name_format = "Release-$(rev:r)"

  artifact {
    alias      = "_build"
    type       = "Build"
    is_primary = true
    definition_reference = {
      definition         = { id = "316" }
      project            = { id = var.project_id }
      defaultVersionType = { id = "latestType" }
    }
  }

  stages {
    name = "Production"
    rank = 1

    deploy_phase {
      name       = "Agent job"
      phase_type = "agentBasedDeployment"
      rank       = 1

      deployment_input {
        queue_id           = data.betterado_agent_pool.default.id
        timeout_in_minutes = 0
      }

      workflow_task {
        task_id      = "e213ff0f-5d5c-4791-802d-52ea3e7be1f1"
        display_name = "Bash Script"
        version_spec = "3.*"
        inputs = {
          targetType = "inline"
          script     = "echo hello"
        }
      }
    }
  }

  variables = {
    "myVar" = {
      value          = "hello"
      is_secret      = false
      allow_override = true
    }
  }
}
```
